	function publicationResult (type = 'post', openPageResult = 0) {
		let token = access_token;
		setPopout(<ScreenSpinner size='large' />);

	        bridge.send("VKWebAppCallAPIMethod", {"method": "photos.getAlbums", "params": {"owner_id": fetchedUser.id, "v":"5.131", "access_token":token}})
		    .then(data_albums => {
		    	let album_id = 0;
		        for (const [key, value] of Object.entries(data_albums["response"]["items"])) {
		        	if(value["title"] == "Перевоплощение") {
		            	album_id = value["id"];
		    		}
		    	}

		        if(album_id == 0 && a == 1) {
		            bridge.send("VKWebAppCallAPIMethod", {"method": "photos.createAlbum", "params": {"title": "Перевоплощение", "description": textAlbum, "v":"5.131", "access_token":token}})
		            .then(data_album => {
		                album_id = data_album["response"]["id"];
		            })

		            .catch(error_album => {
		                setPopout(null);
		                openModal('view_error', null, error_album);
		                return;
		            });
		        }

		        setTimeout(function () {
		        	let paramsUpload = {};
		        	if(a == 1) {
		        		paramsUpload = {"method": "photos.getUploadServer", "params": { "album_id": album_id, "v":"5.131", "access_token":token }};
		        	} else {
		        		paramsUpload = {"method": "photos.getWallUploadServer", "params": {"v":"5.131", "access_token":token }};
		        	}
		        	bridge.send("VKWebAppCallAPIMethod", paramsUpload)
						.then(data_upload => {
							let upload_url = data_upload["response"]["upload_url"];
							let uploadData = new FormData();
							uploadData.append("url", imgPost);
							uploadData.append("upload_url", upload_url);
							axios({
								method: "post",
								url: site + "image?" + getParams,
								data: uploadData
							})
								.then(function (data_post) {
									let paramsSave = {};
									if(a == 1) {
										paramsSave = {"method": "photos.save", "params": { "album_id": album_id, "hash": data_post["data"]["hash"], "server": data_post["data"]["server"], "photos_list": data_post["data"]["photos_list"], "aid": data_post["data"]["aid"], "v":"5.131", "description": textAlbum, "access_token":token }};
									} else {
										paramsSave = {"method": "photos.saveWallPhoto", "params": {"user_id": fetchedUser.id, "server": data_post["data"]["server"], "photo": data_post["data"]["photo"], "hash": data_post["data"]["hash"], "v":"5.131", "caption": textPublication, "access_token":token}};
									}
								  	bridge.send("VKWebAppCallAPIMethod", paramsSave)
										.then(data_save => {
											setPublicationPost("photo"+fetchedUser.id+"_"+data_save["response"][0]["id"]);
											VKImgPost = "photo"+fetchedUser.id+"_"+data_save["response"][0]["id"];
											setPublicationStory(data_save["response"][0]["sizes"][2]["url"]);
											VKImgStory = data_save["response"][0]["sizes"][2]["url"];

		    								if(type == 'post') {
		    									setPopout(null);
		    									openVKPost();
		    									if(openPageResult == 1) {
		    										setActivePanel('result');
		    									}
		    								}
										})

										.catch(function (error_save) {
										    setPopout(null);
										    console.log(error_save);
										    openModal('view_error', null, error_save);
										});
								})

								.catch(function (error_post) {
								    setPopout(null);
								    openModal('view_error', null, {"error_data": {"error_code": 0, "error_reason": "Ошибка загрузки результата"}});
								});
						})

						.catch(error_upload => {
							setPopout(null);
							console.log(error_upload);
							openModal('view_error', null, error_upload);
						});
		        }, 1000);

	        })

	        .catch(error_albums => {
				setPopout(null);
				openModal('view_error', null, error_albums);
			});
	}

